+			return "", fmt.Errorf("getting user cache dir: %w", err)
+		}
+		base = filepath.Join(dir, robotAnalysisDiskCacheDirName)
+	}
+	if create {
+		if err := os.MkdirAll(base, 0o755); err != nil {
