+	t.Logf("Final: heap=%dMB (delta=%dMB) goros=%d (delta=%d) fds=%d (delta=%d) writes=%d snapshots=%d errors=%d",
+		finalMem.Alloc/1024/1024, memDelta/1024/1024,
+		finalGoros, goroDelta,
+		finalFDs, fdDelta,
